    INSERT INTO public.modules (track_id, title, description, order_index) VALUES (web_dev_id, 'Understanding the Web', 'Learn about clients, servers, and how the internet renders pages.', 0) RETURNING id INTO m_id;
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'How the Internet Works', 'video', 0, 30, 20, '{"format": "advanced", "youtubeId": "qz0aGYMCzl0", "description": "Learn about clients, servers, DNS and how devices communicate.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">The Internet is a massive network of networks. Data travels in packets via protocols like TCP/IP. DNS acts as a phonebook translating names to IP addresses.</div></details>", "miniQuiz": [{"question": "What translates domains to IPs?", "options": ["DNS", "HTTP", "TCP", "IP"], "answer": 0}, {"question": "How is data sent?", "options": ["Packets", "Boxes", "Waves", "Wires"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'What Happens When You Type a URL', 'video', 1, 70, 20, '{"format": "advanced", "youtubeId": "dQw4w9WgXcQ", "description": "Step-by-step browser mechanics.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">When you hit Enter, the browser resolves the DNS, initiates a TCP handshake, negotiates TLS, sends an HTTP GET request, and parses the returned HTML.</div></details>", "miniQuiz": [{"question": "What handshake secures a modern connection?", "options": ["TLS", "TCP", "UDP", "FTP"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'What is a Website', 'article', 2, 40, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">What is a Website?</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">A website is essentially a collection of files (HTML, CSS, JS, images) stored on a computer (a **server**) connected to the internet.<br><br><strong style=''color:#ccff00''>Static vs Dynamic</strong><br>Static sites serve the exact same files to everyone. Dynamic sites build pages on the fly using a database (like this one!).</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'How Browsers Render Pages', 'article', 3, 60, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Browser Rendering Lifecycle</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">Browsers are incredibly complex engines. They take HTML and build the <b>DOM (Document Object Model)</b>. They take CSS and build the <b>CSSOM</b>. Then they combine them into a Render Tree, calculate the Layout, and Paint the pixels to your screen.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Web Basics Quiz', 'quiz', 4, 50, 25, '{"questionCount": 20, "passingScore": 18, "topics": ["internet basics", "client-server", "http", "dns"], "questions": [{"question": "What is a web browser?", "options": ["Software to view web pages", "A database", "A gaming engine", "An operating system"], "answer": 0}, {"question": "What does HTTP stand for?", "options": ["HyperText Transfer Protocol", "High Transfer Text", "Hyper Tool Transfer", "Hidden Text Protocol"], "answer": 0}, {"question": "What is the main purpose of DNS?", "options": ["Translating domains to IPs", "Rendering HTML", "Styling pages", "Encrypting data"], "answer": 0}, {"question": "Which port is traditionally used for HTTPS?", "options": ["443", "80", "22", "21"], "answer": 0}, {"question": "What is an IP address?", "options": ["A unique network identifier", "A website''s name", "A type of router", "A computer''s physical address"], "answer": 0}, {"question": "What defines a ''client'' on the web?", "options": ["A device requesting resources", "A server sending data", "A database", "A router"], "answer": 0}, {"question": "What does a ''200 OK'' status mean?", "options": ["Request succeeded", "Page not found", "Server error", "Redirected"], "answer": 0}, {"question": "What is a 404 error?", "options": ["Page Not Found", "Unauthorized", "Bad Gateway", "Internal Server Error"], "answer": 0}, {"question": "What is localhost?", "options": ["The current computer", "A public server", "A DNS server", "A CDN"], "answer": 0}, {"question": "What does a URL do?", "options": ["Locates a resource on the internet", "Compiles code", "Styles a webpage", "Hacks a server"], "answer": 0}, {"question": "Which of these is a Top-Level Domain (TLD)?", "options": [".com", "https", "www", "index"], "answer": 0}, {"question": "What is the function of a web server?", "options": ["To serve files to clients", "To design graphics", "To play videos", "To write code"], "answer": 0}, {"question": "What is an API?", "options": ["A way for software to communicate", "A programming language", "A database model", "A hardware component"], "answer": 0}, {"question": "What is JSON commonly used for?", "options": ["Data exchange between server/client", "Styling pages", "Writing complex logic", "Structuring databases"], "answer": 0}, {"question": "What is caching?", "options": ["Storing data temporarily for speed", "Encrypting passwords", "Deleting history", "Routing traffic"], "answer": 0}, {"question": "What is a cookie in web terms?", "options": ["Small data stored on the client", "A type of database", "A server-side script", "A programming pattern"], "answer": 0}, {"question": "What is a session?", "options": ["Temporary continuous interaction", "A permanent record", "A specific browser", "A type of cookie"], "answer": 0}, {"question": "Why is HTTPS preferred over HTTP?", "options": ["It encrypts the communication", "It is faster", "It looks better", "It is an older standard"], "answer": 0}, {"question": "What does ''frontend'' refer to?", "options": ["The user interface", "The database", "The server logic", "The API"], "answer": 0}, {"question": "What does ''backend'' refer to?", "options": ["Server and database", "The user interface", "The browser", "The CSS"], "answer": 0}]}');
    INSERT INTO public.modules (track_id, title, description, order_index) VALUES (web_dev_id, 'HTML Fundamentals', 'Introduction to HTML tags, elements and structure.', 1) RETURNING id INTO m_id;
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'HTML Crash Course', 'video', 0, 30, 20, '{"format": "advanced", "youtubeId": "qz0aGYMCzl0", "description": "The very core of markup.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">HTML uses tags to structure content. An element is a start tag, content, and an end tag.</div></details>", "miniQuiz": [{"question": "Which is the root tag?", "options": ["<html>", "<body>", "<head>", "<div>"], "answer": 0}, {"question": "What tag defines a paragraph?", "options": ["<p>", "<h1>", "<div>", "<span>"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Understanding Semantic HTML', 'video', 1, 70, 20, '{"format": "advanced", "youtubeId": "qz0aGYMCzl0", "description": "Why div soup is bad.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Semantic HTML (like <article>, <nav>, <main>) provides meaning to the structure, aiding Accessibility (a11y) and SEO.</div></details>", "miniQuiz": [{"question": "Why is semantic HTML good?", "options": ["Accessibility", "It''s faster", "It''s colorful", "It uses less RAM"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Core HTML Tags', 'article', 2, 40, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Essential Tags</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">To build a page, you need to know:<br>- <b>Headings:</b> h1 through h6<br>- <b>Text:</b> p, span, strong, em<br>- <b>Media:</b> img, video, audio<br>- <b>Links:</b> a (anchor tags)</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'HTML Page Structure', 'article', 3, 60, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">The Skeleton</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">Every HTML file needs a `<!DOCTYPE html>` declaration, followed by the `<html>` root, containing a `<head>` (for metadata) and a `<body>` (for visible content).</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Build Your First Webpage', 'challenge', 4, 30, 50, '{"challengeType": "web-ide", "objective": "Create a webpage with a heading, paragraph, image, and a link.", "instructions": "Use h1, p, img, and a tags.", "initialHtml": "<!-- write code here -->", "initialCss": "", "initialJs": "", "validationRules": [], "title": "Build Your First Webpage"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'HTML Quiz', 'quiz', 5, 50, 25, '{"questionCount": 20, "passingScore": 18, "topics": ["tags", "attributes", "elements"], "questions": [{"question": "What does HTML stand for?", "options": ["HyperText Markup Language", "High Text Machine Logic", "Hyper Tool Markup", "Home Text Markup"], "answer": 0}, {"question": "Which tag is the root of an HTML document?", "options": ["<html>", "<body>", "<head>", "<root>"], "answer": 0}, {"question": "Which tag creates a hyper-link?", "options": ["<a>", "<link>", "<href>", "<url>"], "answer": 0}, {"question": "Which tag is used to display an image?", "options": ["<img>", "<pic>", "<image>", "<src>"], "answer": 0}, {"question": "What attribute defines an image source?", "options": ["src", "href", "link", "source"], "answer": 0}, {"question": "Which heading is the largest by default?", "options": ["<h1>", "<h6>", "<header>", "<h0>"], "answer": 0}, {"question": "What tag is used for a paragraph?", "options": ["<p>", "<para>", "<text>", "<pg>"], "answer": 0}, {"question": "How do you make a numbered list?", "options": ["<ol>", "<ul>", "<list>", "<nl>"], "answer": 0}, {"question": "How do you make a bulleted list?", "options": ["<ul>", "<ol>", "<bl>", "<list>"], "answer": 0}, {"question": "What tag defines a list item?", "options": ["<li>", "<item>", "<list>", "<i>"], "answer": 0}, {"question": "Where should the <title> tag be placed?", "options": ["Inside <head>", "Inside <body>", "Outside <html>", "At the very end"], "answer": 0}, {"question": "What is the correct syntax for an HTML comment?", "options": ["<!-- comment -->", "// comment", "/* comment */", "# comment"], "answer": 0}, {"question": "Which tag breaks the line?", "options": ["<br>", "<break>", "<lb>", "<newline>"], "answer": 0}, {"question": "What does the <head> tag contain?", "options": ["Metadata and links", "Visual content", "Footers", "Main article"], "answer": 0}, {"question": "Which tag creates a table?", "options": ["<table>", "<tbl>", "<grid>", "<t>"], "answer": 0}, {"question": "What tag is used for an input field?", "options": ["<input>", "<textfield>", "<form>", "<type>"], "answer": 0}, {"question": "What tag wraps form elements?", "options": ["<form>", "<wrap>", "<fieldset>", "<group>"], "answer": 0}, {"question": "What does the alt attribute do on images?", "options": ["Provides alternate text", "Changes the image", "Styles it", "Makes it bigger"], "answer": 0}, {"question": "Which tag emphasizes text (italic)?", "options": ["<em>", "<i>", "<strong>", "<b>"], "answer": 0}, {"question": "Which tag strongly emphasizes text (bold)?", "options": ["<strong>", "<b>", "<heavy>", "<bold>"], "answer": 0}]}');
    INSERT INTO public.modules (track_id, title, description, order_index) VALUES (web_dev_id, 'CSS Fundamentals', 'Make your websites beautiful with selectors and the box model.', 2) RETURNING id INTO m_id;
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'CSS Basics', 'video', 0, 30, 20, '{"format": "advanced", "youtubeId": "v=1Rs2ND1ryYc", "description": "Styling introduction.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">CSS uses Selectors, Properties, and Values to paint HTML elements.</div></details>", "miniQuiz": [{"question": "What modifies an element?", "options": ["Property", "Tag", "Method", "Array"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Understanding the CSS Box Model', 'video', 1, 70, 20, '{"format": "advanced", "youtubeId": "rIO5326FgPE", "description": "The most important concept in layout.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Everything is a box. Content, wrapped in Padding, wrapped in a Border, spaced out by Margin.</div></details>", "miniQuiz": [{"question": "What is outside the border?", "options": ["Margin", "Padding", "Content", "Outline"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Fonts and Colors', 'article', 2, 40, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Typography & The Palette</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">The web uses HEX, RGB, and HSL to define colors. Typography is managed via `font-family`, `font-weight`, and `line-height`.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Basic Layout Concepts', 'article', 3, 60, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Flow and Layouts</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">By default, the web uses Normal Flow. Block elements stack vertically, Inline elements sit horizontally. We manipulate this using `display: flex` and `display: grid`.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Style Your Profile Page', 'challenge', 4, 30, 50, '{"challengeType": "web-ide", "objective": "Add colors, spacing and layout improvements.", "instructions": "Style the page using CSS. Make the background black and text lime.", "initialHtml": "<h1>Hello</h1>", "initialCss": "body { }", "initialJs": "", "validationRules": [], "title": "Style Your Profile Page"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'CSS Quiz', 'quiz', 5, 50, 25, '{"questionCount": 20, "passingScore": 18, "topics": ["selectors", "box model", "layout"], "questions": [{"question": "What does CSS stand for?", "options": ["Cascading Style Sheets", "Computer Style Sheets", "Creative Style System", "Colorful Style Sheets"], "answer": 0}, {"question": "Which property changes text color?", "options": ["color", "text-color", "font-color", "bgcolor"], "answer": 0}, {"question": "Which property changes background color?", "options": ["background-color", "bg-color", "color-background", "background"], "answer": 0}, {"question": "How do you select an ID in CSS?", "options": ["#id", ".id", "id", "*id"], "answer": 0}, {"question": "How do you select a class in CSS?", "options": [".class", "#class", "class", "*class"], "answer": 0}, {"question": "How do you select all p elements?", "options": ["p", ".p", "#p", "all-p"], "answer": 0}, {"question": "Which property controls text size?", "options": ["font-size", "text-size", "font-style", "size"], "answer": 0}, {"question": "What is the CSS box model comprised of?", "options": ["Margins, borders, padding, content", "Color, font, size", "HTML, CSS, JS", "Only margins and padding"], "answer": 0}, {"question": "What is padding?", "options": ["Space inside the border", "Space outside the border", "The border thickness", "The element''s width"], "answer": 0}, {"question": "What is margin?", "options": ["Space outside the border", "Space inside the border", "The border thickness", "The element''s width"], "answer": 0}, {"question": "How do you make text bold in CSS?", "options": ["font-weight: bold;", "text: bold;", "font: bold;", "style: bold;"], "answer": 0}, {"question": "Which property aligns text?", "options": ["text-align", "align-text", "text-position", "font-align"], "answer": 0}, {"question": "What is the default display value of a block element?", "options": ["block", "inline", "inline-block", "none"], "answer": 0}, {"question": "What is the default display value of a span?", "options": ["inline", "block", "inline-block", "flex"], "answer": 0}, {"question": "What is ''display: flex'' used for?", "options": ["Flexible 1D layouts", "Changing colors", "Making 3D models", "Grid layouts"], "answer": 0}, {"question": "How do you include an external CSS file?", "options": ["<link> in <head>", "<style> in <body>", "<css> tag", "@import in HTML"], "answer": 0}, {"question": "Which unit is relative to the root font size?", "options": ["rem", "px", "em", "vh"], "answer": 0}, {"question": "Which unit is relative to the viewport width?", "options": ["vw", "vh", "%", "px"], "answer": 0}, {"question": "What does ''position: absolute'' do?", "options": ["Positions relative to nearest positioned ancestor", "Positions in normal flow", "Positions relative to viewport", "Fixed to screen"], "answer": 0}, {"question": "What is z-index used for?", "options": ["Stacking order of elements", "Zoom level", "Font size", "Line height"], "answer": 0}]}');
    INSERT INTO public.modules (track_id, title, description, order_index) VALUES (web_dev_id, 'JavaScript Basics', 'Variables, functions and DOM manipulation.', 3) RETURNING id INTO m_id;
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'JavaScript Fundamentals', 'video', 0, 30, 20, '{"format": "advanced", "youtubeId": "W6NZfCO5SIk", "description": "Logic for the web.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">JS gives websites behavior. It uses variables, loops, arrays, objects, and functions.</div></details>", "miniQuiz": [{"question": "How to declare a block-scoped variable?", "options": ["let", "var", "def", "const"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'DOM Manipulation', 'video', 1, 70, 20, '{"format": "advanced", "youtubeId": "y17RuWUpzGw", "description": "Changing the page.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">The DOM is a tree of nodes. JS can query them (`querySelector`) and change their classes, innerHTML, or styles.</div></details>", "miniQuiz": [{"question": "What represents the page?", "options": ["Document Object Model", "Database", "CSSOM", "Server"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'JavaScript Events', 'article', 2, 40, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Handling the User</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">Events are actions that happen to HTML elements (clicks, keystrokes, form submissions). We use `addEventListener()` to execute our functions when these happen.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Connecting JavaScript with HTML', 'article', 3, 60, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Wiring it up</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">JS can be written straight in a `<script>` tag or linked via a `src=\"app.js\"` attribute in the HTML body or head with `defer`.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Button Counter App', 'challenge', 4, 30, 50, '{"challengeType": "web-ide", "objective": "Create a button that increases a counter.", "instructions": "Write the onclick logic.", "initialHtml": "<button id=''btn''>0</button>", "initialCss": "button { padding: 1rem; }", "initialJs": "document.getElementById(''btn'').onclick = function() { }", "validationRules": [], "title": "Button Counter App"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'JS Quiz', 'quiz', 5, 50, 25, '{"questionCount": 20, "passingScore": 18, "topics": ["variables", "functions", "dom"], "questions": [{"question": "Which keyword declares a variable that can be reassigned?", "options": ["let", "const", "var", "set"], "answer": 0}, {"question": "Which keyword declares a constant?", "options": ["const", "let", "var", "readonly"], "answer": 0}, {"question": "How do you write ''Hello World'' in an alert box?", "options": ["alert(''Hello World'');", "msg(''Hello World'');", "alertBox(''Hello World'');", "console.log(''Hello'');"], "answer": 0}, {"question": "How do you define a function in JS?", "options": ["function myFunction()", "def myFunction()", "fn myFunction()", "create myFunction()"], "answer": 0}, {"question": "How do you call a function named ''myFunction''?", "options": ["myFunction()", "call myFunction()", "run myFunction", "myFunction"], "answer": 0}, {"question": "How do you write an IF statement in JS?", "options": ["if (i == 5)", "if i == 5 then", "if i = 5", "if i == 5:"], "answer": 0}, {"question": "How do you write a NOT EQUAL operator?", "options": ["!=", "<>", "!==", "=/="], "answer": 0}, {"question": "Which operator is strict equality?", "options": ["===", "==", "=", "!=="], "answer": 0}, {"question": "How do you start a FOR loop?", "options": ["for (let i = 0; i < 5; i++)", "for (i <= 5)", "for i = 1 to 5", "for i in 5:"], "answer": 0}, {"question": "What does console.log() do?", "options": ["Prints output to browser console", "Shows a popup", "Writes to the document", "Sends data to server"], "answer": 0}, {"question": "How do you add a comment in JS?", "options": ["// comment", "<!-- comment -->", "# comment", "/* comment"], "answer": 0}, {"question": "What is the purpose of an array?", "options": ["To store multiple values", "To define functions", "To style HTML", "To query databases"], "answer": 0}, {"question": "How do you get an element by ID?", "options": ["document.getElementById(''id'')", "document.getId(''id'')", "document.query(''id'')", "window.getElement(''id'')"], "answer": 0}, {"question": "What event fires when an element is clicked?", "options": ["onclick", "onsubmit", "onhover", "onchange"], "answer": 0}, {"question": "What does JSON.stringify do?", "options": ["Converts JS object to JSON string", "Converts JS to HTML", "Parses JSON", "Parses XML"], "answer": 0}, {"question": "What is DOM?", "options": ["Document Object Model", "Data Object Model", "Display Output Machine", "Document Orientation Mode"], "answer": 0}, {"question": "How do you declare a boolean variable?", "options": ["let isTrue = true;", "let isTrue = ''true'';", "bool isTrue = true;", "let isTrue = bool;"], "answer": 0}, {"question": "Which mathematical operator gives the remainder?", "options": ["%", "/", "*", "//"], "answer": 0}, {"question": "How do you concatenate strings?", "options": ["With the + operator", "With the . operator", "With the & operator", "With the concat keyword"], "answer": 0}, {"question": "What is a callback function?", "options": ["A function passed as an argument to another", "A function that ends the program", "A database trigger", "A phone dialer"], "answer": 0}]}');
    INSERT INTO public.modules (track_id, title, description, order_index) VALUES (web_dev_id, 'How Websites Work Together', 'Frontend, Backend, and APIs.', 4) RETURNING id INTO m_id;
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Frontend vs Backend', 'video', 0, 30, 20, '{"format": "advanced", "youtubeId": "XBu54ncBks", "description": "The full stack.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Frontend is the client (browser), backend is the server and database. They communicate over HTTP.</div></details>", "miniQuiz": [{"question": "Where does a database reside?", "options": ["Backend", "Frontend", "Browser", "CSS"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Introduction to APIs', 'video', 1, 70, 20, '{"format": "advanced", "youtubeId": "GZvSYIGsQ", "description": "Application Programming Interfaces.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">APIs allow different pieces of software to talk to each other. On the web, they usually send JSON data.</div></details>", "miniQuiz": [{"question": "What format is common for modern APIs?", "options": ["JSON", "XML", "CSV", "SQL"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Client Server Architecture', 'article', 2, 40, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Request / Response</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">A client makes extreme numbers of HTTP Requests. The server parses the request securely, fetches database items, and sends a Response.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Deploying Your Work', 'article', 3, 60, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Going Live</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">To go live, we put our HTML/CSS/JS frontend on a CDN (Content Delivery Network like Vercel or Netlify) and run our Backend code on a Cloud Provider (AWS, Heroku).</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Architecture Quiz', 'quiz', 5, 50, 25, '{"questionCount": 20, "passingScore": 18, "topics": ["architecture", "apis", "databases"], "questions": [{"question": "What part of an application interacts directly with the user?", "options": ["Frontend", "Backend", "Database", "API"], "answer": 0}, {"question": "What handles server logic and database communication?", "options": ["Backend", "Frontend", "CSS", "HTML"], "answer": 0}, {"question": "What acts as a bridge between frontend and backend?", "options": ["API", "Database", "Browser", "Operating System"], "answer": 0}, {"question": "What is REST?", "options": ["An architectural style for APIs", "A programming language", "A database model", "A frontend framework"], "answer": 0}, {"question": "What is an endpoint?", "options": ["A specific URL an API exposes", "The end of a program", "A database table", "A crashed server"], "answer": 0}, {"question": "Which HTTP method is typically used to create a resource?", "options": ["POST", "GET", "PUT", "DELETE"], "answer": 0}, {"question": "Which HTTP method is typically used to fetch data?", "options": ["GET", "POST", "DELETE", "PATCH"], "answer": 0}, {"question": "What does a database schema define?", "options": ["The structure of the data", "The API endpoints", "The visual layout", "The server IP"], "answer": 0}, {"question": "What is a relational database?", "options": ["Data stored in tables with relationships", "Data stored as JSON documents", "Data stored as files", "A frontend component"], "answer": 0}, {"question": "What is SQL used for?", "options": ["Querying relational databases", "Styling websites", "Handling browser events", "Configuring routers"], "answer": 0}, {"question": "What is NoSQL?", "options": ["Non-relational databases", "A broken SQL query", "A fast frontend", "A type of API"], "answer": 0}, {"question": "What does CRUD stand for?", "options": ["Create, Read, Update, Delete", "Compile, Read, Upload, Deploy", "Create, Run, Use, Delete", "Code, Release, Update, Debug"], "answer": 0}, {"question": "What is Authentication?", "options": ["Verifying who a user is", "Determining what a user can do", "Encrypting data", "Hashing a password"], "answer": 0}, {"question": "What is Authorization?", "options": ["Determining what a user is allowed to do", "Verifying who a user is", "Deploying code", "Logging users out"], "answer": 0}, {"question": "What is a JWT?", "options": ["JSON Web Token", "Java Web Tool", "JavaScript Wrapper Template", "Join With Tables"], "answer": 0}, {"question": "What is deployment?", "options": ["Making an application live on servers", "Writing code locally", "Pushing to GitHub", "Testing locally"], "answer": 0}, {"question": "What is a serverless architecture?", "options": ["Servers are managed by cloud providers automatically", "There are literally no physical servers", "Only frontends exist", "Code runs on local machines only"], "answer": 0}, {"question": "What does CI/CD stand for?", "options": ["Continuous Integration / Continuous Deployment", "Code Integration / Code Delivery", "Client Integration / Client Deployment", "Create Insert / Create Delete"], "answer": 0}, {"question": "What is version control?", "options": ["Tracking changes in code over time", "Controlling database versions", "Updating node.js", "Styling versions"], "answer": 0}, {"question": "Which tool is most commonly used for version control?", "options": ["Git", "Docker", "Nginx", "PostgreSQL"], "answer": 0}]}');
    INSERT INTO public.modules (track_id, title, description, order_index) VALUES (dsa_id, 'Programming Logic', 'Understanding how computers solve problems step-by-step.', 0) RETURNING id INTO m_id;
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'What is Programming Logic', 'video', 0, 30, 20, '{"format": "advanced", "youtubeId": "v4cd1O4zkGw", "description": "Thinking like a computer.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Computers are extremely fast but fundamentally dumb. You must tell them exactly what to do using explicit logic.</div></details>", "miniQuiz": [{"question": "Are computers inherently smart?", "options": ["No", "Yes", "Sometimes", "Always"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Computational Thinking', 'video', 1, 70, 20, '{"format": "advanced", "youtubeId": "v4cd1O4zkGw", "description": "Breaking problems down.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Algorithms, Decompositions, Abstraction, and Pattern Recognition.</div></details>", "miniQuiz": [{"question": "What is breaking down a problem called?", "options": ["Decomposition", "Abstraction", "Building", "Crumbling"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Algorithms Explained', 'article', 2, 40, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">The Algorithm</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">An algorithm is nothing more than a precise sequence of instructions designed to solve a specific problem.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Steps in Problem Solving', 'article', 3, 60, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">The Methodology</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">1. Understand the problem.<br>2. Decompose into parts.<br>3. Design the logic (Pseudo-code, flowchart).<br>4. Write the code.<br>5. Test iteratively.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Find the Larger Number', 'challenge', 4, 30, 50, '{"challengeType": "flowchart", "objective": "Compare two numbers.", "requiredNodes": ["Start", "Input", "Decision", "End"], "task": "Output the larger.", "title": "Find the Larger Number"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Logic Quiz', 'quiz', 5, 50, 25, '{"questionCount": 20, "passingScore": 18, "topics": ["logic", "algorithmic thinking"], "questions": [{"question": "What is an algorithm?", "options": ["A step-by-step procedure to solve a problem", "A programming language", "A piece of hardware", "A type of database"], "answer": 0}, {"question": "What is computational thinking?", "options": ["Solving problems logically like a computer", "Fast typing", "Thinking in machine code", "Using AI"], "answer": 0}, {"question": "In a flowchart, what shape is typically a decision?", "options": ["Diamond", "Rectangle", "Oval", "Parallelogram"], "answer": 0}, {"question": "In a flowchart, what shape represents start/end?", "options": ["Oval", "Diamond", "Rectangle", "Arrow"], "answer": 0}, {"question": "What is decomposition in problem-solving?", "options": ["Breaking a complex problem into smaller parts", "Deleting code", "Rotting data", "Combining functions"], "answer": 0}, {"question": "What is pattern recognition?", "options": ["Identifying similarities to solve problems faster", "Regex", "Visual design", "Machine learning"], "answer": 0}, {"question": "What is abstraction?", "options": ["Hiding complex details to focus on essentials", "Drawing random shapes", "Extracting large datasets", "A type of class"], "answer": 0}, {"question": "Why is logic important in programming?", "options": ["It ensures code does what it is supposed to do", "It makes the code colorful", "It makes text bolder", "It avoids using RAM"], "answer": 0}, {"question": "Which is a valid boolean value?", "options": ["True", "''True''", "1", "Yes"], "answer": 0}, {"question": "What is an edge case?", "options": ["An extreme or unusual situation in a problem", "The border of a UI element", "A physical laptop edge", "A fast algorithm"], "answer": 0}, {"question": "What is a syntax error?", "options": ["Violating the rules of the programming language", "A logic flaw", "A server crash", "A broken monitor"], "answer": 0}, {"question": "What is a logic error?", "options": ["Code runs but produces incorrect results", "Code won''t compile", "A typo in a keyword", "Database disconnected"], "answer": 0}, {"question": "What does pseudo-code mean?", "options": ["A plain-language description of an algorithm", "Fake encrypted code", "Machine code", "CSS syntax"], "answer": 0}, {"question": "What is iteration?", "options": ["Repeating a process", "Deciding between true/false", "Storing data", "Logging an error"], "answer": 0}, {"question": "What is branching?", "options": ["Executing different paths based on a condition", "Copying code files", "A looping structure", "A database relation"], "answer": 0}, {"question": "Which logical operator means ''both must be true''?", "options": ["AND", "OR", "NOT", "XOR"], "answer": 0}, {"question": "Which logical operator means ''at least one is true''?", "options": ["OR", "AND", "NOT", "XNOR"], "answer": 0}, {"question": "How does a computer read instructions?", "options": ["Sequentially unless directed otherwise", "Randomly", "Bottom to top", "All at once"], "answer": 0}, {"question": "What implies problem-solving efficiency?", "options": ["Using the fewest resources or steps necessary", "Writing the longest code", "Ignoring errors", "Using big fonts"], "answer": 0}, {"question": "How do you test a logical algorithm?", "options": ["Provide various inputs and check outputs", "Read it", "Print it out", "Upload it"], "answer": 0}]}');
    INSERT INTO public.modules (track_id, title, description, order_index) VALUES (dsa_id, 'Variables and Data', 'How programs store and manipulate data.', 1) RETURNING id INTO m_id;
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Understanding Variables', 'video', 0, 30, 20, '{"format": "advanced", "youtubeId": "v4cd1O4zkGw", "description": "Memory boxes.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Variables are named boxes in computer RAM. Creating one allocates space, assigning it fills the space.</div></details>", "miniQuiz": [{"question": "What does a variable do?", "options": ["Stores data", "Renders UI", "Creates a server", "Deletes files"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Inputs and Outputs', 'video', 1, 70, 20, '{"format": "advanced", "youtubeId": "v4cd1O4zkGw", "description": "Communicating.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Algorithms take inputs, process them using variables and logic, and produce outputs.</div></details>", "miniQuiz": [{"question": "What does processing do?", "options": ["Transforms input to output", "Creates databases", "Runs monitors", "Makes coffee"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Basic Data Types', 'article', 2, 40, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Integers, Strings, Booleans</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">You must know how to categorize data. Numbers (Int/Float) allow math. Strings allow text formatting. Booleans allow binary logic.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Updating Values', 'article', 3, 60, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Reassignment</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">Software states are dynamic. A score starts at 0, and becomes `score = score + 1`. This concept of state mutation is essential.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Add Two Numbers', 'challenge', 4, 30, 50, '{"challengeType": "flowchart", "objective": "Sum them.", "requiredNodes": ["Start", "Input", "Process", "End"], "task": "Calc sum.", "title": "Add Two Numbers"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Data Quiz', 'quiz', 5, 50, 25, '{"questionCount": 20, "passingScore": 18, "topics": ["variables", "types", "mutation"], "questions": [{"question": "What is a variable?", "options": ["A named storage location in memory", "A database table", "A type of loop", "An error condition"], "answer": 0}, {"question": "What is a data type?", "options": ["A classification of the type of data a variable holds", "A function", "An API", "A keyboard layout"], "answer": 0}, {"question": "Which of these is an Integer?", "options": ["42", "''42''", "42.5", "True"], "answer": 0}, {"question": "Which of these is a Float (or Double)?", "options": ["3.14", "3", "''3.14''", "False"], "answer": 0}, {"question": "Which of these is a String?", "options": ["''Hello''", "True", "50", "null"], "answer": 0}, {"question": "Which of these is a Boolean?", "options": ["True", "''True''", "1", "''Yes''"], "answer": 0}, {"question": "What does assignment mean?", "options": ["Giving a variable a value", "Creating a function", "Deleting data", "A school task"], "answer": 0}, {"question": "What is an array?", "options": ["An ordered collection of items", "A mathematical function", "A single text string", "A boolean"], "answer": 0}, {"question": "How are array elements typically indexed?", "options": ["Starting from 0", "Starting from 1", "Starting from A", "Randomly"], "answer": 0}, {"question": "What does immutability mean?", "options": ["Cannot be changed after creation", "Can be changed", "Is invisible", "Requires a password"], "answer": 0}, {"question": "What is a constant?", "options": ["A variable whose value cannot change", "An infinite loop", "A number", "A string"], "answer": 0}, {"question": "What happens when you overwrite a variable?", "options": ["The old memory is cleared/replaced with the new value", "The computer crashes", "It creates a new variable", "Values combine"], "answer": 0}, {"question": "What does type casting mean?", "options": ["Converting a variable from one data type to another", "Creating a new class", "Throwing an error", "Streaming video"], "answer": 0}, {"question": "What is a dynamically typed language?", "options": ["Variable types determined at runtime", "Variable types defined before compiling", "Variables change color", "Types do not exist"], "answer": 0}, {"question": "What is null or None?", "options": ["Represents the intentional absence of any value", "Zero", "An empty string", "An error"], "answer": 0}, {"question": "What is the difference between = and == ?", "options": ["= assigns, == compares", "= compares, == assigns", "They are the same", "Neither exists"], "answer": 0}, {"question": "If x=5, what is x+5?", "options": ["10", "55", "''55''", "Error"], "answer": 0}, {"question": "If x=''5'' and y=''5'', what is x+y in typical languages?", "options": ["''55''", "10", "0", "Error"], "answer": 0}, {"question": "What is garbage collection?", "options": ["Automatic memory management", "Deleting old code lines", "Clearing cache", "Emptying the trash bin"], "answer": 0}, {"question": "What is the scope of a variable?", "options": ["The region of code where it is accessible", "Its data type", "Its value", "Its memory address"], "answer": 0}]}');
    INSERT INTO public.modules (track_id, title, description, order_index) VALUES (dsa_id, 'Conditionals', 'Using conditions to control program flow.', 2) RETURNING id INTO m_id;
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'If Statements', 'video', 0, 30, 20, '{"format": "advanced", "youtubeId": "v4cd1O4zkGw", "description": "Branching logic.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Without if statements, code runs linearly. If statements allow logic to react to dynamic inputs.</div></details>", "miniQuiz": [{"question": "What keyword allows branching?", "options": ["if", "var", "run", "route"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Decision Making in Programs', 'video', 1, 70, 20, '{"format": "advanced", "youtubeId": "v4cd1O4zkGw", "description": "Logical evaluation.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Conditions evaluate to True or False. Logical Operators (AND, OR, NOT) string conditions together.</div></details>", "miniQuiz": [{"question": "Which requires both sides to be true?", "options": ["AND", "OR", "NOT", "XOR"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'If vs If Else', 'article', 2, 40, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Alternate Paths</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">Use `if` for a single detour. Use `else` to provide a fallback. Use `else if` to chain mutually exclusive routes.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Nested Conditions', 'article', 3, 60, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Deep Logic</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">Putting if blocks inside of if blocks allows complex matrices of logic, though it can lead to deeply indented ''spaghetti'' code if abused.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Even or Odd', 'challenge', 4, 30, 50, '{"challengeType": "flowchart", "objective": "Use modulo.", "requiredNodes": ["Start", "Decision", "End"], "task": "N % 2 == 0.", "title": "Even or Odd"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Conditionals Quiz', 'quiz', 5, 50, 25, '{"questionCount": 20, "passingScore": 18, "topics": ["if", "else", "booleans"], "questions": [{"question": "What does an IF statement do?", "options": ["Executes code conditionally", "Loops endlessly", "Defines a variable", "Prints text"], "answer": 0}, {"question": "What is an ELSE block?", "options": ["Code that runs if the IF condition is false", "Code that runs before an IF", "A type of error", "A loop"], "answer": 0}, {"question": "What is ELSE IF (elif)?", "options": ["Checks a new condition if the first IF was false", "Restarts the program", "Deletes the IF", "A bug"], "answer": 0}, {"question": "Which operator means ''greater than''?", "options": [">", "<", ">=", "=="], "answer": 0}, {"question": "What does <= mean?", "options": ["Less than or equal to", "Greater than or equal to", "Not equal to", "Equal to"], "answer": 0}, {"question": "If x=10, is x>5 True or False?", "options": ["True", "False", "Neither", "Error"], "answer": 0}, {"question": "If a=True and b=False, what is a AND b?", "options": ["False", "True", "1", "0"], "answer": 0}, {"question": "If a=True and b=False, what is a OR b?", "options": ["True", "False", "1", "0"], "answer": 0}, {"question": "What is a nested conditional?", "options": ["An IF statement inside another IF statement", "A loop inside an IF", "Multiple variables", "A syntax error"], "answer": 0}, {"question": "What is a Switch or Match statement?", "options": ["Compares one value against many cases", "Switches computer state", "A network router", "Turns off the screen"], "answer": 0}, {"question": "When evaluating ''5 == 5 AND 10 == 2'', what is the result?", "options": ["False", "True", "Error", "10"], "answer": 0}, {"question": "What results from NOT True?", "options": ["False", "True", "Null", "Undecided"], "answer": 0}, {"question": "Why use multiple ELSE IFs?", "options": ["To check mutually exclusive conditions", "To run all code blocks", "To slow the program", "To replace loops"], "answer": 0}, {"question": "Can an IF statement exist without an ELSE?", "options": ["Yes", "No", "Depends", "Only in Python"], "answer": 0}, {"question": "What is a ternary operator?", "options": ["A shorthand inline if-else", "A math function", "Three loops", "A type of dataset"], "answer": 0}, {"question": "If age=18, does (age >= 18) evaluate to true?", "options": ["Yes", "No", "It causes an error", "Null"], "answer": 0}, {"question": "What causes dead code in conditionals?", "options": ["Conditions that can logically never be reached", "Too many variables", "Fast processors", "Using IF instead of ELSE"], "answer": 0}, {"question": "What is truthiness?", "options": ["Values that evaluate to true in a boolean context", "The absolute truth", "Honesty in code", "A string"], "answer": 0}, {"question": "Does 0 typically evaluate as truthy or falsy?", "options": ["Falsy", "Truthy", "Neither", "Error"], "answer": 0}, {"question": "Does an empty string '''' typically evaluate as falsy?", "options": ["Yes", "No", "Depends", "Error"], "answer": 0}]}');
    INSERT INTO public.modules (track_id, title, description, order_index) VALUES (dsa_id, 'Loops and Iteration', 'Running repeated instructions.', 3) RETURNING id INTO m_id;
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'For Loops', 'video', 0, 30, 20, '{"format": "advanced", "youtubeId": "v4cd1O4zkGw", "description": "Specific counts.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Used when you know exactly how many times you want to iterate (e.g. going through every item in a 10-item array).</div></details>", "miniQuiz": [{"question": "When are FOR loops best?", "options": ["Known iteration counts", "Unknown iterations", "Database queries", "Styling"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'While Loops', 'video', 1, 70, 20, '{"format": "advanced", "youtubeId": "v4cd1O4zkGw", "description": "Until a condition breaks.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Used when the loop should run indefinitely until a specific condition evaluates to false.</div></details>", "miniQuiz": [{"question": "What happens if the condition is always true?", "options": ["Infinite loop", "Error", "Ends instantly", "Speeds up"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Iteration Concepts', 'article', 2, 40, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Repetition</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">Iterating involves traversing data structures. We use an index counter (`i`) to access sequential elements repeatedly without writing thousands of lines of code.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Avoiding Infinite Loops', 'article', 3, 60, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">The CPU Killer</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">An infinite loop occurs when the break condition is impossible to reach. Always ensure loop counters mutate appropriately inside the loop.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Print Numbers 1 to 10', 'challenge', 4, 30, 50, '{"challengeType": "flowchart", "objective": "Iterate 1 to 10.", "requiredNodes": ["Start", "Loop", "End"], "task": "Print.", "title": "Print Numbers"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Loops Quiz', 'quiz', 5, 50, 25, '{"questionCount": 20, "passingScore": 18, "topics": ["loops", "iteration", "while"], "questions": [{"question": "What is a loop used for?", "options": ["To repeat a block of code", "To stop the program", "To define variables", "To query databases"], "answer": 0}, {"question": "What is an infinite loop?", "options": ["A loop whose termination condition is never reached", "A loop over all numbers", "A loop in a loop", "A fast loop"], "answer": 0}, {"question": "What is a FOR loop best suited for?", "options": ["Iterating a specific number of times", "Waiting for user input", "Defining constants", "Quitting an app"], "answer": 0}, {"question": "What is a WHILE loop best suited for?", "options": ["Iterating until a condition becomes false", "Counting from 1 to 10", "Iterating through an array", "It is obsolete"], "answer": 0}, {"question": "What does a ''break'' statement do?", "options": ["Exits the loop immediately", "Skips an iteration", "Breaks the computer", "Crashes the app"], "answer": 0}, {"question": "What does a ''continue'' statement do?", "options": ["Skips the rest of the current iteration and proceeds to the next", "Exits the loop", "Pauses the program", "Ends the program"], "answer": 0}, {"question": "What is a nested loop?", "options": ["A loop within a loop", "A loop that never ends", "A UI component", "An array"], "answer": 0}, {"question": "If a loop runs from i=0 to i<5, how many times does it run?", "options": ["5", "4", "6", "0"], "answer": 0}, {"question": "What is an iteration?", "options": ["A single execution of the loop body", "A variable", "A syntax error", "A database row"], "answer": 0}, {"question": "What is a common cause of an off-by-one error?", "options": ["Incorrect loop boundaries (e.g., using <= instead of <)", "Typing 1 instead of l", "Slow CPU", "Broken keyboard"], "answer": 0}, {"question": "What goes in a traditional FOR loop header?", "options": ["Initialization, Condition, Increment", "Variable, String, Output", "Condition only", "Input, Output"], "answer": 0}, {"question": "When using a WHILE loop, where must the condition be modified?", "options": ["Inside the loop body", "Before the loop", "After the loop", "Nowhere"], "answer": 0}, {"question": "What is traversing?", "options": ["Visiting every element in a data structure using a loop", "Crossing logic gates", "Deleting elements", "Creating an array"], "answer": 0}, {"question": "How do you stop an infinite loop in a terminal?", "options": ["Ctrl + C", "Alt + F4", "Esc", "Enter"], "answer": 0}, {"question": "What is a counter variable?", "options": ["A variable that increments during each loop pass", "A variable storing strings", "A constant", "A boolean"], "answer": 0}, {"question": "Can loops iterate backwards?", "options": ["Yes", "No", "Depends", "Only in C++"], "answer": 0}, {"question": "What is a do-while loop?", "options": ["A loop that executes at least once before checking the condition", "A fast while loop", "A loop that only does things", "A syntax error"], "answer": 0}, {"question": "If i=10 and i--, what is i?", "options": ["9", "11", "10", "-10"], "answer": 0}, {"question": "What is an accumulator?", "options": ["A variable used to sum up values inside a loop", "A type of array", "A loop keyword", "A hardware component"], "answer": 0}, {"question": "What does iterating over an array mean?", "options": ["Accessing each item in the array sequentially", "Deleting the array", "Sorting the array", "Shuffling"], "answer": 0}]}');
    INSERT INTO public.modules (track_id, title, description, order_index) VALUES (dsa_id, 'Basic Algorithm Design', 'Structured approaches to solving problems.', 4) RETURNING id INTO m_id;
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'What is an Algorithm', 'video', 0, 30, 20, '{"format": "advanced", "youtubeId": "v4cd1O4zkGw", "description": "Structured solutions.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Software Engineering heavily relies on proven algorithms to sort, search, and navigate large spaces.</div></details>", "miniQuiz": [{"question": "What is typically analyzed for an algorithm?", "options": ["Efficiency", "Length", "Spelling", "Lines"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Designing Efficient Steps', 'video', 1, 70, 20, '{"format": "advanced", "youtubeId": "v4cd1O4zkGw", "description": "Optimization basics.", "summaryRenderer": "<details style=\"padding: 1rem; border: 1px solid #333; border-radius: 8px; background: #0a0a0a; margin-top: 1rem;\"><summary style=\"color: #ccff00; cursor: pointer; font-weight: 700;\">&#9658; View Topic Summary</summary><div style=\"color: #f5f5f5; margin-top: 1rem; line-height: 1.6;\">Doing something in 1 step versus 1,000 steps matters at scale.</div></details>", "miniQuiz": [{"question": "What is Big O?", "options": ["Performance notation", "A loop", "A variable", "A database"], "answer": 0}]}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Intro to Time Complexity', 'article', 2, 40, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Big O Notation</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">Big O measures how the execution time grows relative to input size. O(1) is instant, O(N) is linear, O(N^2) (nested loops) is sluggish at scale.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Combining Loops and Conditions', 'article', 3, 60, 15, '{"markdown": "<div style=\"color: #f5f5bd; background-color: #000; padding: 2rem; border-radius: 12px; border: 1px solid #1a1a1a;\"><h1 style=\"color: #ccff00; border-bottom: 2px solid #1a1a1a; padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-weight: 800;\">Real World Logic</h1><div style=\"font-size: 1.15rem; line-height: 1.8;\">Most powerful algorithms utilize loops containing decisions. For example, ''Loop through all users, IF they are active, send them an email''.</div></div>"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Sum of Numbers 1 to N', 'challenge', 4, 30, 50, '{"challengeType": "flowchart", "objective": "Calculate sum using a loop and accumulator.", "requiredNodes": ["Start", "Loop", "End"], "task": "Sum up.", "title": "Sum of Numbers"}');
    INSERT INTO public.topics (module_id, title, type, order_index, position_x, xp_reward, content_data) VALUES (m_id, 'Algorithm Design Quiz', 'quiz', 5, 50, 25, '{"questionCount": 20, "passingScore": 18, "topics": ["big-o", "efficiency", "optimization"], "questions": [{"question": "What is Time Complexity?", "options": ["How execution time grows with input size", "How long code took to write", "How many times it crashes", "Delay of the CPU"], "answer": 0}, {"question": "What is the notation used for Time Complexity?", "options": ["Big O Notation", "Big C Notation", "Little O Notation", "Theta Grid"], "answer": 0}, {"question": "What is O(1)?", "options": ["Constant time", "Linear time", "Quadratic time", "Exponential time"], "answer": 0}, {"question": "What is O(N)?", "options": ["Linear time", "Constant time", "Quadratic time", "Exponential time"], "answer": 0}, {"question": "What is O(N^2)?", "options": ["Quadratic time", "Linear time", "Constant time", "Logarithmic time"], "answer": 0}, {"question": "Which is generally faster for very large inputs?", "options": ["O(1)", "O(N)", "O(N^2)", "O(N^3)"], "answer": 0}, {"question": "What is Space Complexity?", "options": ["How memory usage grows with input size", "How much storage a laptop has", "Database size", "HTML dimensions"], "answer": 0}, {"question": "What complexity does a simple loop from 1 to N have?", "options": ["O(N)", "O(1)", "O(N^2)", "O(log N)"], "answer": 0}, {"question": "What complexity does a nested loop typically have?", "options": ["O(N^2)", "O(N)", "O(1)", "O(log N)"], "answer": 0}, {"question": "What is a linear search?", "options": ["Checking each element one by one", "Jumping around randomly", "Checking only the middle", "Using a hash map"], "answer": 0}, {"question": "What does algorithm efficiency measure?", "options": ["Time and Space used", "Lines of code", "Number of variables", "Syntax correctness"], "answer": 0}, {"question": "What is the worst-case scenario?", "options": ["The input that requires the maximum steps", "The app crashing", "Losing power", "The shortest time"], "answer": 0}, {"question": "What is sorting?", "options": ["Arranging data in a specific order", "Finding a value", "Deleting data", "Adding new items"], "answer": 0}, {"question": "What happens when you combine an O(N) loop and an independent O(N) loop?", "options": ["The overall complexity is still O(N)", "It becomes O(N^2)", "It becomes O(1)", "It becomes error"], "answer": 0}, {"question": "What happens to execution time of O(N) if input size doubles?", "options": ["It roughly doubles", "It stays same", "It quadruples", "It halves"], "answer": 0}, {"question": "What happens to execution time of O(N^2) if input size doubles?", "options": ["It quadruples", "It doubles", "It stays same", "It halves"], "answer": 0}, {"question": "What is brute force?", "options": ["Trying every single possible solution", "A very fast algorithm", "A hardware upgrade", "A hacking mechanism"], "answer": 0}, {"question": "What is optimization?", "options": ["Improving an algorithm to use fewer resources", "Making a UI prettier", "Adding more comments", "Writing longer code"], "answer": 0}, {"question": "Is O(log N) faster than O(N) for large N?", "options": ["Yes", "No", "They are identical", "Depends on the language"], "answer": 0}, {"question": "Why do we care about algorithm design?", "options": ["To ensure software remains fast and scales efficiently", "To write more lines of code", "To increase app download size", "To use more RAM"], "answer": 0}]}');
